import React, { useContext, useEffect, useState } from "react";
import axios from "axios";
import { UserContext } from "../context/UserContext";
import { Clothes } from "../components/Clothes";
export const UsersListing = () => {

    const [clothes ,setClothes] = useState([])
    const {user} = useContext(UserContext)

    useEffect(()=>{
        if(user)
        {
          axios.defaults.headers.common.Authorization = `Bearer ${user.token}`;
          axios.get('/items/get')
          .then((data)=>{
            setClothes(data.data.item)
          })
        }
      },[user])

  return (
    <div>
        <div>
          {
             console.log(clothes.length)
          }
        {
         
         clothes.length > 0 ?
          clothes.map((data,index)=>{
            return (
              <div className="bg-red-500 flex flex-col ">
              <Clothes props={data} key={index}/>
              </div>  
              )
            })
          :
            <div className="flex  mt-8 justify-center">
            <div className="w-64 h-24 bg-red-400 flex justify-center items-center font-semibold"> 
              You Have Zero Listings 
            </div>
              </div>
        } 
        </div>
    </div>
  )
}
